  const FOOT_DUST_SPACING = 14;    // 角色每移動約這麼多像素揚一撮塵（越小越密）
  const footDust = [];             // [{wx,wy,vx,vy,life,ttl,size,r,g,b}]
  const _footLastPos = new Map();  // 角色 id → {x,y,acc} 上次取樣位置與未滿一格的累積位移
  let _footDustLast = 0;           // 上次更新時間（推 dt）
