  const settings = { smartAutoDig: false, predict: true };
  try { settings.smartAutoDig = localStorage.getItem("butfun.smartAutoDig") === "1"; } catch {}
  try { settings.predict = localStorage.getItem("butfun.predict") !== "0"; } catch {}
