  const ENEMY_DEATH_FADE_MS = 600;
  let enemyDeathFade = []; // 每槽 { until:ms } or undefined
  // 是否已同步過初始敵人快照。和乙太/背包/血量同理:進場/重連的第一份快照不拿來比 hp 差值
  // (伺服器若換版重啟,敵人血量可能不同,會誤閃一輪),之後的快照差值才是真的受擊。
  let enemiesSynced = false;
  // 採集判定半徑(像素),與伺服器 GATHER_REACH 對齊:玩家離節點這麼近才採得到。
  const GATHER_REACH = 56;
  // 主動攻擊判定半徑(像素),與伺服器 ATTACK_REACH 對齊。
  const ATTACK_REACH = 64;
  // 主動攻擊客戶端冷卻(毫秒):與伺服器 ATTACK_COOLDOWN_SECS 對齊,避免多按狂送。
  const ATTACK_COOLDOWN_MS = 600;
  let lastAttackTime = 0;
  // 最近一次快照數到「自己那塊」有作物且缺水的格數（updateFarmHud 算好順手記下）；
  // 給離田時的「回農地」邊緣指標決定要不要強調缺水，數字與 HUD 一致、不另外再數一遍。
  let farmDryCount = 0;
  // 同上,數到「自己那塊」已成熟可收成（state 4）的格數。種田迴圈的回報這一步先前沒有
  // 任何離田指標——澆水這個雜務有缺水提醒,收成這個甜頭卻沒,玩家走遠就不知道乙太已熟在等。
  // 補一個讓「收成迴圈的回報」也一眼可讀,數字與 HUD 一致、給邊緣指標共用。
  let farmRipeCount = 0;
  let myEther = 0;
  // 是否已同步過初始乙太：避免進場／重連時把既有存量當成一次大量「獲得」而噴一大串飄字。
  let etherKnown = false;
  // 上一次快照的背包數量（item → qty）+ 是否已同步過初始背包。和乙太同理:進場/重連時
  // 既有存量不算「採到」,不噴飄字;之後某品項數量變多才是真的採進來,才噴「+N 🪵」。
  let myInv = new Map();
  let invKnown = false;
  let lastBagSig = ""; // 背包面板上次重繪時的內容簽章——只在變了才重繪，避免每幀砍掉重建按鈕
  // C-4 建造：玩家從背包選取的放置材料（"dirt"/"stone" 或 null 表示未選）。
  // 右鍵點空格時若有選取材料且背包有貨則送 place；按 Escape 或再次點同項取消選取。
  let selectedBuildMaterial = null;
  // 上一次快照的生命值 + 是否已同步過初始生命。和乙太/背包同理:進場/重連時不把既有血量
  // 當成「掉血/回血」播報;之後血量變化才是真的受擊或恢復。戰鬥(1-F)剛上線、HP 有 HUD
  // 但看不到畫面的玩家完全收不到受擊——補這條把無障礙弧線延伸到戰鬥(連線/採集/收成/日夜之後)。
  let myHp = 0;
  let hpKnown = false;
  let wasDownedLastTick = false; // 上一快照是否倒地，用於偵測「傳回新手村」瞬間
  let myLevel = null; // 上一快照等級，用於偵測升級
  let _lastAchCount = null; // 成就數量基準，用於偵測新解鎖（ROADMAP 376）
  let myFurniture = []; // 住家家具列表（ROADMAP 155）：快照帶回的已放置家具陣列
  let myHomeStyle = "wood_cabin"; // 居家風格主題（ROADMAP 325）：快照帶回的風格代碼，預設木屋
  // 受擊時畫面邊緣紅光一閃(damage vignette):看得到畫面的玩家受擊時,HUD 只有一個小數字在變、
  // 移動中很容易漏看「我正在挨打」。報讀器那條已補受擊播報(給看不到畫面的玩家),這條是它對稱的
  // 視覺版——純表現,從權威 HP 差值觸發,不嵌任何規則。記下「閃到何時為止」,render 依剩餘時間淡出。
  let damageFlashUntil = 0;
  let damageFlashLethal = false; // 被打趴(hp<=0)時閃得更重一點
  // 精英血條（ROADMAP 386）：視野內有兇名精英時頂端大型 HP 血條。
  const BOSS_BAR_REACH = 520; // 感知半徑（世界像素）
  let _bossBarAlpha = 0;       // 渲染 alpha [0,1]，淡入淡出
  let _bossBarBoss = null;     // 目前鎖定的兇名敵人快照（EnemyView Object 或 null）
  // 收成得乙太、採集進背包時的「+N」飄字（純表現，從權威數值差值推得，不嵌任何遊戲規則）。
  // 每筆 { wx, wy, text, color, born }：以世界座標固定在獲得當下的玩家位置上方，隨時間上飄淡出。
  const floaters = [];
  // ROADMAP 346 釣魚結果飄字對照（魚 key → 中文名／emoji；反應品質 → 中文標籤）。
  const FISH_NAME_BY_KEY = { fish_small: "小魚", fish_star: "星星魚", fish_deep: "深海魚" };
  const FISH_EMOJI_BY_KEY = { fish_small: "🐟", fish_star: "⭐", fish_deep: "🦈" };
  const FISH_QUALITY_LABEL = { ok: "上鉤", good: "漂亮", perfect: "完美" };
  // ROADMAP 363 季節漁汛：四季各有「當季當紅魚」。**此表必須與後端 fishing_bite::signature_fish
  // 完全同步**（後端是權威擲骰，前端僅據此顯示提示與慶祝，不可各說各話）。
  const SEASON_FISHING_RUN = { spring: "春汛", summer: "夏汛", autumn: "秋汛", winter: "冬汛" };
  const SEASON_SIGNATURE_FISH = { spring: "fish_star", summer: "fish_small", autumn: "fish_deep", winter: "fish_star" };
  // 互動確認漣漪（純表現）：點/輕點田格送出農作意圖時，在該格畫一圈短暫擴張淡出的亮環，
  // 讓玩家「按下就有回饋」——尤其手機沒有桌面的 hover 高亮,輕點後到下一個快照回來前
  // 全無反饋會覺得沒點到。每筆 { wx, wy, born }（世界座標,鏡頭移動也黏在原格）。不嵌任何
  // 遊戲規則:做不做得成仍由權威伺服器決定,這裡只確認「這一下送出去了」。
  const tapFlashes = [];
  // 採集「動作」特效（治「點擊沒有採集動作」）:每次採集在目標節點記一筆揮擊 { wx, wy, born, kind },
  // 用來畫衝擊星芒 + 讓那顆節點短暫晃動;同時噴出資源碎屑(下方 gatherParticles)。
  const gatherHits = [];
  // 採集碎屑:每筆 { wx, wy, vx, vy, born, color } 從節點向外飛、受重力、淡出。純表現。
  const gatherParticles = [];
  // 主動攻擊命中特效:每筆 { wx, wy, born } 在敵人位置畫一下紅色衝擊圈。純表現。
  const attackHits = [];
  // 怪物王重擊衝擊波（ROADMAP 424）：每筆 { wx, wy, radius, born } 在落點畫一圈向外炸開、擴張到
  // 重擊半徑後淡去的紅色衝擊環。純表現（傷害已由伺服器結算），收到 boss_slam 廣播時 push。
  const bossSlams = [];
  // 豐收迸發（ROADMAP 458）：收成成熟作物的那一刻，在收成者身上迸開一抹金光＋揚起一捧金穀。
  // 採集樹石礦早有 drawGatherFx 的星芒＋碎屑回饋，收成卻一直只有「+N 乙太」飄字、世界畫面悄無聲息；
  // 本陣列補上收成這個高頻療癒動作的世界格上對等回饋。harvestBursts＝中心金光暈 { wx, wy, born, quality }；
  // harvestGrains＝向上揚起的金穀粒子 { wx, wy, vx, vy, born, color }。純表現、不嵌規則。
  const harvestBursts = [];
  const harvestGrains = [];
  // 圍爐分食（ROADMAP 462）：有人在旅人身旁吃下暖食料理時，香氣分給附近的人——
  // 在吃飯者腳下飄一陣暖食香氣。mealAromas＝中心暖香暈＋🍲 { wx, wy, born }；
  // mealAromaWisps＝向上飄散的熱氣縷 { wx, wy, drift, born }。純表現、不嵌規則（受惠者
  // 頭頂的暖食光暈本就隨快照 well_fed 同步亮起，此陣列只演「分食的那一瞬」）。
  const mealAromas = [];
  const mealAromaWisps = [];
  // 同伴扶起（ROADMAP 464）：有人把倒下的旅人扶起來時，在被救者起身處迸一道暖光救援特效。
  // reviveGlows＝向外擴散的暖光環＋🤝 { wx, wy, born }。純表現、不嵌規則（被救者血條本就
  // 隨快照血量同步回滿一半，此陣列只演「被扶起的那一瞬」）。
  const reviveGlows = [];
  // 伺服器廣播的日夜狀態 { phase, light }；進場前為 null（render 時當白天、不疊夜色）。
  let daynight = null;
  let worldEvent = null; // { x, y, remaining_secs } | null — 來自伺服器快照的宇宙裂縫事件
  // 裂縫事件 → 狀態列小 pill（取代會壓到血量列的頂部大橫幅）。同字不重寫 DOM。
  let lastEventPillText = null;
  let hordeEvent = null; // { phase, site_x, site_y, site_label, secs_left } | null — 獸潮攻城（ROADMAP 44）
  // 天地有名（ROADMAP 398）：當前所在「在地地名」（伺服器權威），小地圖角落常駐顯示。
  let myLocale = null;   // { name, subtitle } | null
  // 踏入新地方時的淡入地名卡（reduceMotion 下略過動畫，直接不彈卡只更新標）。
  let localeCard = null; // { name, subtitle, born } | null
  let lastHordeBannerText = null; // 防止重複 DOM 操作
  function updateWorldEventPill(ev) {
    const pill = document.getElementById("hudEvent");
    if (!pill) return;
    const text = ev ? `🌀 ${Math.ceil(ev.remaining_secs)}s` : null;
    if (text === lastEventPillText) return;
    lastEventPillText = text;
    if (text) {
      pill.textContent = text;
      pill.title = `宇宙裂縫開啟！(${Math.round(ev.x)}, ${Math.round(ev.y)})——看小地圖 🌀 標記`;
      pill.classList.remove("hidden");
    } else {
      pill.classList.add("hidden");
    }
  }
  // 獸潮攻城橫幅（ROADMAP 44）：廣播倒數或攻城進行中時顯示頂部橫幅。
  function updateHordeBanner(ev) {
    let banner = document.getElementById("hordeBanner");
    if (!ev) {
      if (banner) { banner.style.display = "none"; }
      lastHordeBannerText = null;
      return;
    }
    const label = ev.site_label || "";
    const secs  = ev.secs_left || 0;
    let text, bgColor;
    if (ev.phase === "announcing") {
      text    = `⚔️ 獸潮即將衝擊 ${label}！${secs}s 後開始`;
      bgColor = "#7a2020";
    } else {
      text    = `⚔️ 獸潮攻城 ${label}！迎戰剩餘 ${secs}s（打退 6 隻贏全服獎勵）`;
      bgColor = "#5a1010";
    }
    if (text === lastHordeBannerText) return;
    lastHordeBannerText = text;
    if (!banner) {
      banner = document.createElement("div");
      banner.id = "hordeBanner";
      banner.style.cssText = [
        "position:fixed", "top:0", "left:0", "right:0",
        "z-index:9990", "text-align:center",
        "font-size:.85rem", "font-weight:600",
        "padding:5px 12px", "pointer-events:none",
        "letter-spacing:.02em",
      ].join(";");
      document.body.appendChild(banner);
    }
    banner.style.background  = bgColor;
    banner.style.color        = "#f8d0a0";
    banner.style.display      = "block";
    banner.textContent        = text;
  }

  // HUD 右側橫幅欄（HUD 抗重疊 v1）：過去 7 條狀態橫幅（節慶/聚會/繁榮/星象/流星雨/旅行商人/
  // 季節）各自寫死 position:fixed;top:Npx;right:8px——隱藏時留空洞、又會跟左上「會換行的狀態列
  // pill 牆」在窄手機上撞在一起（旅行商人蓋住夜晚/回城）。改成全部收進一個自動堆疊的 flex 直欄：
  // 隱藏的（display:none）自動收合不留洞、整欄往右上收齊、寬度上限避免插進狀態列。各橫幅用
  // style.order 維持穩定上下順序，與創建先後無關。
  function _ensureBannerColumn() {
    let col = document.getElementById("hudBanners");
    if (!col) {
      col = document.createElement("div");
      col.id = "hudBanners";
      col.style.cssText = [
        "position:fixed",
        "top:calc(48px + env(safe-area-inset-top))",
        "right:calc(8px + env(safe-area-inset-right))",
        "display:flex", "flex-direction:column", "align-items:flex-end",
        "gap:4px", "max-width:min(72vw,260px)",
        "z-index:1000", "pointer-events:none",
      ].join(";");
      document.body.appendChild(col);
    }
    return col;
  }

  // 拉皮：右上 banner 欄只該留「臨時全服事件」，且最多露 2-3 條——多的折成一顆「+N 則」徽。
  // 每幀末跑一次：數出目前真正顯示中的事件 pill，超過上限就把多的暫時藏起、補一顆計數徽；
  // 季節/未分配點等常駐資訊已收回頂部狀態列，不再進這欄。純前端表現、不動任何事件邏輯。
  const BANNER_VISIBLE_CAP = 3;       // 同時最多露幾條全服事件 pill
  let _lastBannerFoldText = null;     // 折疊徽上次文字，變了才改 DOM
  function _bannerPillVisible(el) {
    // 判斷一條 banner pill「在折疊以外」是否本該顯示——折疊用獨立 class 不碰各 update*Hud
    // 寫的 inline display，這裡先排除折疊 class 再判斷其真實意圖（display!=none 且非 .hidden）。
    if (!el || el.id === "hudBannerMore") return false;
    if (el.classList && el.classList.contains("hidden")) return false;
    return el.style.display !== "none";
  }
  function foldBannerColumn() {
    const col = document.getElementById("hudBanners");
    if (!col) return;
    const all = Array.from(col.children).filter((el) => el.id !== "hudBannerMore");
    // 先卸下上一輪的折疊 class，讓每條 pill 回到各自 update*Hud 寫的真實顯隱意圖（折疊用 class
    // 帶 !important，不覆蓋 inline display，因此各 update 的早退快取仍正確、不會被我們攪亂）。
    for (const el of all) el.classList.remove("banner-folded");
    const shown = all.filter(_bannerPillVisible);
    let more = document.getElementById("hudBannerMore");
    if (shown.length <= BANNER_VISIBLE_CAP) {
      if (more) more.style.display = "none";
      _lastBannerFoldText = null;
      return;
    }
    const overflow = shown.slice(BANNER_VISIBLE_CAP);
    for (const el of overflow) el.classList.add("banner-folded");
    if (!more) {
      more = document.createElement("div");
      more.id = "hudBannerMore";
      more.style.cssText = [
        "order:99",
        "background:var(--panel-solid)", "color:var(--ink-dim)",
        "border:1px solid var(--hairline)", "border-radius:var(--r-pill)",
        "font-size:.75rem", "font-weight:600", "padding:3px 10px",
      ].join(";");
      more.title = "還有其他進行中的全服事件（點開狀態欄查看）";
      _ensureBannerColumn().appendChild(more);
    }
    const text = `＋${overflow.length} 則事件`;
    if (text !== _lastBannerFoldText) { more.textContent = text; _lastBannerFoldText = text; }
    more.style.display = "block";
  }

