        const spt = Math.abs(Math.sin(now / 90)); // 與身體頂撞同步、一脹一縮，像力道的一推一退
        ctx.globalAlpha = 0.55 + 0.4 * spt;
        ctx.font = `${11 + spt * 2}px ${UI_FONT}`; // 隨頂撞節奏一脹一縮
        ctx.textAlign = "center";
        ctx.textBaseline = "bottom";
