        const bloom = 1.0 + Math.abs(Math.sin(now / 540)) * 0.22; // 和緩脹縮 [1.0, 1.22]，湊近嗅花的呼吸起伏
        ctx.globalAlpha = 0.65 + 0.3 * Math.abs(Math.sin(now / 540)); // 隨呼吸微微明滅
