        ctx.globalAlpha = 0.55 + 0.4 * ct;
        ctx.font = `11px ${UI_FONT}`;
        ctx.textAlign = "center";
        ctx.textBaseline = "bottom";
        ctx.translate(7, -23 - ct * 3); // 像音符隨鳴聲輕輕上下跳動
        // ROADMAP 306：黃昏暮鳴——黃昏（daynight.phase==="dusk"）與破曉同為合唱時辰，皆畫一串更密的
